/* Base clinical luxury components — host for audit extension (repo-local). */

/* NUVANX — componentes para auditoría editorial páginas 06–24.
 * La escala usa únicamente tokens múltiplos de 8px.
 */

.nvx-audit-module {
  width: 100%;
  padding-block: var(--nvx-space-12);
  background: var(--nvx-white);
  color: var(--nvx-clinical-ink);
}

.nvx-audit-module--soft {
  background: var(--nvx-pearl);
}

.nvx-audit-module__inner {
  width: var(--nvx-shell);
  max-width: 100%;
  margin-inline: auto;
  padding-inline: var(--nvx-gutter-inner);
  box-sizing: border-box;
}

.nvx-audit-module__header {
  display: grid;
  gap: var(--nvx-space-2);
  max-width: 64ch;
  margin-bottom: var(--nvx-space-8);
}

.nvx-audit-module__header > * {
  margin: 0;
}

.nvx-audit-module__eyebrow {
  font-family: var(--nvx-sans);
  font-size: var(--nvx-type-kicker);
  font-weight: var(--nvx-fw-semibold);
  line-height: var(--nvx-lh-kicker);
  letter-spacing: var(--nvx-track-kicker);
  text-transform: uppercase;
  color: var(--nvx-accent-bronze);
}

.nvx-audit-module__title {
  max-width: 24ch;
  font-family: var(--nvx-serif);
  font-size: var(--nvx-type-h2);
  font-weight: var(--nvx-fw-regular);
  line-height: var(--nvx-lh-h2);
  letter-spacing: var(--nvx-track-h2);
  color: var(--nvx-clinical-ink);
  text-wrap: balance;
}

.nvx-audit-module__lead {
  max-width: 64ch;
  font-family: var(--nvx-sans);
  font-size: var(--nvx-type-lead);
  line-height: var(--nvx-lh-lead);
  color: var(--nvx-clinical-muted);
}

.nvx-decision-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: var(--nvx-space-6);
  margin-block: var(--nvx-space-8);
}

.nvx-decision-card {
  min-width: 0;
  padding: var(--nvx-space-4);
  border-top: 1px solid var(--nvx-clinical-line);
  background: var(--nvx-white);
}

.nvx-decision-card__number {
  display: block;
  margin-bottom: var(--nvx-space-3);
  font-family: var(--nvx-sans);
  font-size: var(--nvx-type-kicker);
  font-weight: var(--nvx-fw-semibold);
  letter-spacing: var(--nvx-track-kicker);
  color: var(--nvx-accent-bronze);
}

.nvx-decision-card__title {
  margin: 0 0 var(--nvx-space-2);
  font-family: var(--nvx-serif);
  font-size: var(--nvx-type-h3);
  font-weight: var(--nvx-fw-regular);
  line-height: var(--nvx-lh-h3);
  color: var(--nvx-clinical-ink);
}

.nvx-decision-card__text {
  max-width: 60ch;
  margin: 0;
  font-family: var(--nvx-sans);
  font-size: var(--nvx-type-body);
  line-height: var(--nvx-lh-body);
  color: var(--nvx-clinical-muted);
}

.nvx-audit-callout {
  max-width: 72ch;
  margin-block: var(--nvx-space-8);
  padding: var(--nvx-space-4);
  border-left: 2px solid var(--nvx-accent-bronze);
  background: var(--nvx-pearl);
}

.nvx-audit-callout__title {
  margin: 0 0 var(--nvx-space-2);
  font-family: var(--nvx-serif);
  font-size: var(--nvx-type-h3);
  line-height: var(--nvx-lh-h3);
  color: var(--nvx-clinical-ink);
}

.nvx-audit-callout__text {
  margin: 0;
  font-family: var(--nvx-sans);
  font-size: var(--nvx-type-body);
  line-height: var(--nvx-lh-body);
  color: var(--nvx-clinical-muted);
}

.nvx-audit-module__faq {
  max-width: 72ch;
  margin-top: var(--nvx-space-8);
  border-top: 1px solid var(--nvx-clinical-line);
}

.nvx-audit-module__faq details {
  border-bottom: 1px solid var(--nvx-clinical-line);
}

.nvx-audit-module__faq summary {
  position: relative;
  padding: var(--nvx-space-3) var(--nvx-space-6) var(--nvx-space-3) 0;
  list-style: none;
  font-family: var(--nvx-serif);
  font-size: var(--nvx-type-h3);
  line-height: var(--nvx-lh-h3);
  color: var(--nvx-clinical-ink);
  cursor: pointer;
}

.nvx-audit-module__faq summary::-webkit-details-marker {
  display: none;
}

.nvx-audit-module__faq summary::after {
  content: "+";
  position: absolute;
  top: var(--nvx-space-3);
  right: var(--nvx-space-1);
  color: var(--nvx-accent-bronze);
}

.nvx-audit-module__faq details[open] summary::after {
  content: "−";
}

.nvx-audit-module__answer {
  max-width: 64ch;
  padding-bottom: var(--nvx-space-4);
}

.nvx-audit-module__answer p {
  margin: 0;
  font-family: var(--nvx-sans);
  font-size: var(--nvx-type-body);
  line-height: var(--nvx-lh-body);
  color: var(--nvx-clinical-muted);
}

.nvx-legal-document {
  max-width: 72ch;
  margin-inline: auto;
  padding: var(--nvx-space-6);
  border: 1px solid var(--nvx-clinical-line);
  border-radius: var(--nvx-space-3);
  background: var(--nvx-white);
}

.nvx-status-panel {
  max-width: 72ch;
  margin-block: var(--nvx-space-8);
  padding: var(--nvx-space-4);
  border: 1px solid rgba(197, 168, 128, 0.40);
  border-radius: var(--nvx-space-3);
  background: var(--nvx-action-bg);
  color: var(--nvx-action-text);
}

.nvx-status-panel__title {
  margin: 0 0 var(--nvx-space-2);
  font-family: var(--nvx-serif);
  font-size: var(--nvx-type-h3);
  color: var(--nvx-action-text);
}

.nvx-status-panel__text {
  margin: 0;
  font-family: var(--nvx-sans);
  font-size: var(--nvx-type-body);
  line-height: var(--nvx-lh-body);
  color: rgba(245, 232, 216, 0.80);
}

@media (max-width: 960px) {
  .nvx-decision-grid {
    grid-template-columns: 1fr;
    gap: var(--nvx-space-4);
  }
}

@media (max-width: 720px) {
  .nvx-audit-module {
    padding-block: var(--nvx-space-8);
  }

  .nvx-audit-module__header {
    margin-bottom: var(--nvx-space-6);
  }

  .nvx-decision-card,
  .nvx-audit-callout,
  .nvx-legal-document,
  .nvx-status-panel {
    padding: var(--nvx-space-3);
  }
}
